/// <summary>
/// Extension class for LedgerAccrualTrans Class
/// </summary>
[ExtensionOf(classStr(LedgerAccrualTrans))]
public final class ETGLedgerAccrualTrans_Extension
{
    public LedgerJournalTrans ledgerJournalTrans;

}

Method.Source:
public static LedgerAccrualTrans construct(LedgerJournalTransAccrual _ledgerJournalTransAccrual)
{
    LedgerAccrualTrans  ledgerAccrualTrans;

    ledgerAccrualTrans = next construct(_ledgerJournalTransAccrual);

    if (ETGACFParameters::find().EnableAccrualSchemePostingMonthly)
    {
        LedgerAccrualTable  ledgerAccrualTable = LedgerAccrualTable::find(_ledgerJournalTransAccrual.AccrualId);


        ledgerAccrualTrans = new ETGLedgerAccrualTransPost();

        ledgerAccrualTrans.parmLedgerJournalTransAccrual(_ledgerJournalTransAccrual);
        ledgerAccrualTrans.parmLedgerAccrualTable(ledgerAccrualTable);
        ledgerAccrualTrans.parmCalendarRecId(CompanyInfoHelper::fiscalCalendarRecId());
    }

    return ledgerAccrualTrans;
}

public LedgerDimensionAccount getOffsetLedgerDimension(AmountCur _amountCur)
{
    LedgerDimensionDefaultAccount defaultLedgerDimension = (_amountCur < 0 ? ledgerAccrualTable.CreditLedgerDimension : ledgerAccrualTable.DebitLedgerDimension);

    LedgerDimensionAccount mergedLedgerDimension = next getOffsetLedgerDimension(_amountCur);

    ETGLedgerJournalTransAccrual etgLedgerJournalTransAccrual = ETGLedgerJournalTransAccrual::find(ledgerJournalTrans.TableId,ledgerJournalTrans.RecId);

    if (etgLedgerJournalTransAccrual.Accountoffsetaccount == AccountOffsetaccount::OffsetAccount)
    {
        mergedLedgerDimension = LedgerDimensionFacade::serviceMergeLedgerDimensions(defaultLedgerDimension, ledgerJournaltrans.OffsetLedgerDimension);
    }
    else
    {
        mergedLedgerDimension = LedgerDimensionFacade::serviceMergeLedgerDimensions(defaultLedgerDimension, ledgerJournaltrans.LedgerDimension);
    }

    return mergedLedgerDimension;
}
